﻿/*******************************************************************
 * Class Name: Delegates
 * Purpose: a class to contain all the delegate methods,
 *          used for accessing Windows forms controls
 *          outside the main form thread.
 * Author: Hila Shmuel, 
 * Date: 03/09/2011
 *******************************************************************/

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Windows.Forms;

namespace Delegates
{
    public class Delegates
    {
        private delegate void SetTextDelegate(TextBox text_box, string text);
        private delegate int GetTrackBarValueDelegate(TrackBar trackBar);
        private delegate void SetEnabledDelegate(Control controller, bool enabled);

        private SetTextDelegate SetTextCallback;
        private GetTrackBarValueDelegate GetTrackBarValueCallback;
        private SetEnabledDelegate SetEnabledCallback;

        public Delegates()
        {
            SetTextCallback = this.SetText;
            GetTrackBarValueCallback = this.GetTrackBarValue;
            SetEnabledCallback = this.SetEnabled;
        }

        /***************************************************************************************
         * SET & GET User-Interface controls methods - DONT USE THEM! (hence the "private")
         ***************************************************************************************/
        private void SetText(TextBox text_box, string text)
        {
            text_box.Text = text;
        }

        private int GetTrackBarValue(TrackBar trackBar)
        {
            return trackBar.Value;
        }

        private void SetEnabled(Control controller, bool enabled)
        {
            controller.Enabled = enabled;
        }

        /***************************************************************************************
         * SET & GET User-Interface controls methods - USE ONLY THEM!
         ***************************************************************************************/
        public void SetControlText(System.Windows.Forms.Form form, Control control, string text)
        {
            if (control == null)
            {
                return;
            }
            else if (control.InvokeRequired)
            {
                form.BeginInvoke(SetTextCallback, new object[] { control, text });
            }
            else
            {
                control.Text = text;
            }
        }

        public void SetControlEnabled(System.Windows.Forms.Form form, Control controller, bool enabled)
        {
            if (controller == null)
            {
                return;
            }
            if (controller.InvokeRequired)
            {
                form.BeginInvoke(SetEnabledCallback, new object[] { controller, enabled });
            }
            else
            {
                controller.Enabled = enabled;
            }
        }
    }
}

﻿/*******************************************************************
 * Class Name: FilesHandler
 * Purpose: handle the program's output files formats:
 *          ABC, PostScript, PDF, Wave, MIDI.
 *          
 *          given a list of Notes, outputs the file containing
 *          the corresponding music data.
 *          
 * Author: Hila Shmuel, 
 * Date: 0`4/09/2011
 *******************************************************************/

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.IO;
using System.Configuration;
using Notes;

namespace Recorder
{
    /// <summary>
    /// FilesHandler exception class
    /// </summary>
    public class FilesHandlerException : System.Exception
    {
        /// <summary>
        /// FilesHandler exception
        /// </summary>
        /// <param name="reason">String describing the cause of the error</param>
        public FilesHandlerException(string reason) : base(reason) { }
    }

    /// <summary>
    /// Class that Handles converting from .abc file to .ps to  .pdf
    /// </summary>
    static class FilesHandler
    {
        static public void CreateABCfile(RecordingData recordingData, string ABCfilePath)
        {
            try
            {
                FileStream ABCfile = System.IO.File.Create(ABCfilePath);

                // Write ABC file header
                string endl = "\r\n";
                AddText(ABCfile, "X:1" + endl);
                AddText(ABCfile, "T:" + recordingData.Title + endl);
                AddText(ABCfile, "C:" + recordingData.Composer + endl);
                AddText(ABCfile, "M:C" + endl);
                AddText(ABCfile, "L:1/4" + endl);
                AddText(ABCfile, "K:C" + endl); // Can be C or F

                // Write ABC file data - notes
                foreach (Note note in recordingData.Notes)
                {
                    AddText(ABCfile, note.ABC + " ");
                }

                ABCfile.Close();
            }
            catch (Exception ex)
            {
                string error_message = "FilesHandler Error: create ABC file failed:\n" + ex.Message;
                throw new FilesHandlerException(error_message);
            }
        }

        static public void CreatePostScriptFileFromABC(string ABCfilePath, string postScriptFilePath)
        {
            try
            {
                System.Diagnostics.Process pProcess = new System.Diagnostics.Process();
                pProcess.StartInfo.FileName = Properties.Settings.Default.abcm2psPath;
                pProcess.StartInfo.Arguments = "\"" + ABCfilePath + "\" -O \"" + postScriptFilePath + "\"";
                pProcess.StartInfo.UseShellExecute = false;
                pProcess.StartInfo.RedirectStandardOutput = false;
                pProcess.StartInfo.CreateNoWindow = true;
                pProcess.StartInfo.WorkingDirectory = System.IO.Path.GetTempPath();
                pProcess.Start();
                pProcess.WaitForExit();
            }
            catch (Exception ex)
            {
                string error_message = "FilesHandler Error: Error in convertin from .abc file to .ps file\n" + ex.Message;
                throw new FilesHandlerException(error_message);
            }
        }

        static public void CreatePostScriptfile(RecordingData recordingData, string postScriptFilePath)
        {
            try
            {
                string guid = Guid.NewGuid().ToString();
                string tmpPath = System.IO.Path.GetTempPath();
                string ABCfilePath = tmpPath + guid + ".abc";

                CreateABCfile(recordingData, ABCfilePath);
                CreatePostScriptFileFromABC(ABCfilePath, postScriptFilePath);

                File.Delete(ABCfilePath);
            }
            catch (Exception ex)
            {
                string error_message = "FilesHandler Error: create PostScript file failed:" + ex.Message;
                throw new FilesHandlerException(error_message);
            }
        }

        static public void CreatePDFfileFromPostScript(string postScriptFilePath, string PDFfilePath)
        {
            try
            {
                System.Diagnostics.Process pProcess = new System.Diagnostics.Process();
                pProcess.StartInfo.FileName = Properties.Settings.Default.GhostScriptPath;
                pProcess.StartInfo.Arguments = "-sDEVICE=pdfwrite -o \"" + PDFfilePath + "\" \"" + postScriptFilePath + "\"";
                pProcess.StartInfo.UseShellExecute = false;
                pProcess.StartInfo.RedirectStandardOutput = false;
                pProcess.StartInfo.CreateNoWindow = true;
                pProcess.StartInfo.WorkingDirectory = System.IO.Path.GetTempPath();
                pProcess.Start();
                pProcess.WaitForExit();
            }
            catch (Exception ex)
            {
                string error_message = "FilesHandler Error: Error in convertin from .ps file to .pdf file\n" + ex.Message;
                throw new FilesHandlerException(error_message);
            }
        }

        static public void CreatePDFfileFromABC(string ABCfilePath, string PDFfilePath)
        {
            try
            {
                string guid = Guid.NewGuid().ToString();
                string tmpPath = System.IO.Path.GetTempPath();
                string postScriptFilePath = tmpPath + guid + ".ps";

                CreatePostScriptFileFromABC(ABCfilePath, postScriptFilePath);
                CreatePDFfileFromPostScript(postScriptFilePath, PDFfilePath);

                File.Delete(postScriptFilePath);
            }
            catch (Exception ex)
            {
                string error_message = "FilesHandler Error: converting from .abc to .pdf failed" + ex.Message;
                throw new FilesHandlerException(error_message);
            }
        }

        static public void CreatePDFfile(RecordingData recordingData, string PDFfilePath)
        {
            try
            {
                string guid = Guid.NewGuid().ToString();
                string tmpPath = System.IO.Path.GetTempPath();
                string postScriptFilePath = tmpPath + guid + ".ps";

                CreatePostScriptfile(recordingData, postScriptFilePath);
                CreatePDFfileFromPostScript(postScriptFilePath, PDFfilePath);

                File.Delete(postScriptFilePath);
            }
            catch (Exception ex)
            {
                string error_message = "FilesHandler Error: creating PDF file failed" + ex.Message;
                throw new FilesHandlerException(error_message);
            }
        }

        private static void AddText(System.IO.FileStream fs, string value)
        {
            byte[] info = new UTF8Encoding(true).GetBytes(value);
            fs.Write(info, 0, info.Length);
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Drawing;
using Notes;

namespace Recorder
{
    class FingeringChart
    {
        NoteDrawer noteDrawer;
        List<Note> notes;

        public FingeringChart()
        {
            noteDrawer = new NoteDrawer();
            notes = new List<Note>();

            NotesDB notesDB = new NotesDB();
            for (byte MIDI = 72; MIDI <= 99; MIDI++)
            {
                Note note = notesDB.GetNote(MIDI);
                if (null != note)
                {
                    notes.Add(note);
                }
            }         
        }

        public Note GetNoteOnLocation(Point location)
        {
            return noteDrawer.GetNoteOnLocation(location);
        }

        public void Draw(Graphics graphics, Brush brush)
        {
            Color background = Color.White;
            noteDrawer = new NoteDrawer();
            for (int i = 0; i < notes.Count; i++)
            {
                noteDrawer.Draw(graphics, background, brush, brush, notes[i]);
            }
        }
    }
}

﻿/*******************************************************************
 * Class Name: RecorderFingerings
 * Purpose: given a note & octave, create a picture of the recorder
 *          with the proper fingerings
 * Author: Hila Shmuel, 
 * Date: 19/08/2011
 *******************************************************************/
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Drawing;
using System.IO;
using System.Text.RegularExpressions;
using Notes;

namespace Recorder
{
    enum HoleStatus { Covered, HalfCovered, Uncovered };

    public class RecorderFingeringsException : System.Exception
    {
        public RecorderFingeringsException(string reason) : base(reason) { }
    }


    class FingeringsPicture
    {
        const short recorderHolesNumber = 8;

        Image instrumentPicture;
        RecorderFingerings recorderFingerings;
        RecorderHoles recorderHoles;


        public FingeringsPicture()
        {
            instrumentPicture = Recorder.Properties.Resources.RecorderPicture;
            recorderFingerings = new RecorderFingerings(Recorder.Properties.Resources.recorderFingering);
            recorderHoles = new RecorderHoles(Recorder.Properties.Resources.recorderPictureHoles);    
        }

        public void createPicture(Graphics graph, Note note)
        {
            HoleStatus[] fingerings = recorderFingerings.getNoteFingerings(note);
            Image image = new Bitmap(instrumentPicture);
            Graphics ImageGraphics = Graphics.FromImage(image);
            Brush brush = new SolidBrush(Color.Black);

            if (null != fingerings)
            {
                for (byte holeIndex = 0; holeIndex < recorderHolesNumber; holeIndex++)
                {
                    if (fingerings[holeIndex] == HoleStatus.Covered)
                    {
                        ImageGraphics.FillEllipse(brush, recorderHoles.getHoleLocation(holeIndex));
                    }
                    else if (fingerings[holeIndex] == HoleStatus.HalfCovered)
                    {
                        ImageGraphics.FillPie(brush, recorderHoles.getHoleLocation(holeIndex),-90, 180);
                    }
                    else if (fingerings[holeIndex] == HoleStatus.Uncovered)
                    {
                        // do nothing
                    }
                }
            }

            graph.DrawImage(image, 0, 0);
        }
    }

    class RecorderFingerings
    {
        const short MaxMIDI = 100;
        const short recorderHolesNumber = 8;
        HoleStatus[][] fingeringsTable;

        public RecorderFingerings(string recorderFingerings)
        {
            fingeringsTable = new HoleStatus[MaxMIDI][];

            string[] lines = Regex.Split(recorderFingerings, "\r\n");

            foreach (string noteFingering in lines)
            {
                addNoteFingerings(fingeringsTable, noteFingering);
            }
        }

        static private void addNoteFingerings(HoleStatus[][] fingeringsTable, string noteFingering)
        {
            string[] tokens = noteFingering.Split(';');

            short MIDIindex = Convert.ToInt16(tokens[0]);
            fingeringsTable[MIDIindex] = new HoleStatus[recorderHolesNumber];

            for (int i = 0; i < recorderHolesNumber; i++)
            {
                switch (tokens[i + 1])
                {
                    case "c":
                        fingeringsTable[MIDIindex][i] = HoleStatus.Covered;
                        break;
                    case "h":
                        fingeringsTable[MIDIindex][i] = HoleStatus.HalfCovered;
                        break;
                    case "u":
                        fingeringsTable[MIDIindex][i] = HoleStatus.Uncovered;
                        break;
                    default:
                        throw new RecorderFingeringsException("parsing the fingering input invalid" +
                            "for note number: " + tokens[0] + " at index: " + i.ToString());
                }
            }
        }

        public HoleStatus[] getNoteFingerings(Note note)
        {
            if (null == note)
            {
                return null;
            }
            else if (0 <= note.MIDI && note.MIDI < fingeringsTable.Length)
            {
                return fingeringsTable[note.MIDI];
            }
            else
            {
                return null;
            }
        }
    }

    class RecorderHoles
    {
        const short recorderHolesNumber = 8;
        Rectangle[] holesLocationsTable;

        public RecorderHoles(string recorderHoles)
        {
            holesLocationsTable = new Rectangle[recorderHolesNumber];

            string[] lines = Regex.Split(recorderHoles, "\r\n");
            foreach (string holeLocation in lines)
            {
                addHoleLocation(holesLocationsTable, holeLocation);
            }
        }

        static private void addHoleLocation(Rectangle[] holesLocationsTable, string holeLocation)
        {
            string[] tokens = holeLocation.Split(';');

            short holeIndex = Convert.ToInt16(tokens[0]);

            int x = Convert.ToInt16(tokens[1]) -5 ;
            int y = Convert.ToInt16(tokens[2]) -5;
            int width = Convert.ToInt16(tokens[3]);
            int height = Convert.ToInt16(tokens[4]);

            holesLocationsTable[holeIndex] = new Rectangle(x, y, width, height);
        }

        public Rectangle getHoleLocation(short holeIndex)
        {
            return holesLocationsTable[holeIndex];
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Linq;
