        private float GetTrackBarSleepMultiplier()
        {
            float precent = trackBarRecorderHero.Value;

            if (precent <= 50)
            {
                return (-9F / 50F) * precent + 10F;
            }
            else
            {
                return (-9F / 500F) * precent + 1.9F;
            }
        }

