using System;
using System.Runtime.InteropServices;

namespace PInvokeLibrary
{
	/// <summary>
	/// Contains methods for allocating and freeing memory.
	/// </summary>
	public class Memory
	{
		/// <summary>
		/// Allocates fixed memory. The return value is a pointer to the memory object.
		/// </summary>
		public const uint LMEM_FIXED = 0x0000;
		/// <summary>
		/// Initializes memory contents to zero.
		/// </summary>
		public const uint LMEM_ZEROINIT = 0x0040;
		/// <summary>
		/// Enables the memory allocation to move if it cannot be allocated in place.
		/// </summary>
		public const uint LMEM_MOVEABLE = 0x0002;
		/// <summary>
		/// Allows modification of the attributes of the memory object.
		/// </summary>
		public const uint LMEM_MODIFY = 0x0080;

		/// <summary>
		/// This function allocates the specified number of bytes from the heap. In
		/// the linear Microsoft� Windows� CE application programming interface (API)
		/// environment, there is no difference between the local heap and the global
		/// heap.
		/// </summary>
		/// <param name="uFlags">[in] Specifies how to allocate memory. If zero is
		/// specified, the default is the LMEM_FIXED flag. This parameter is a combination
		/// of LMEM_FIXED and LMEM_ZEROINIT. </param>
		/// <param name="uBytes">[in] Specifies the number of bytes to allocate.</param>
		/// <returns>A handle to the newly allocated memory object indicates success.
		/// NULL indicates failure. To get extended error information,
		/// call GetLastError.</returns>
		[DllImport("Kernel32.dll")]
		extern public static IntPtr LocalAlloc(uint uFlags, uint uBytes); 

		/// <summary>
		/// This function frees the specified local memory object and invalidates its handle.
		/// </summary>
		/// <param name="hMem">Handle to the local memory object. This handle is returned
		/// by either the LocalAlloc or LocalReAlloc function.</param>
		/// <returns>NULL indicates success. A handle to the local memory object indicates
		/// failure. To get extended error information, call GetLastError.</returns>
		[DllImport("Kernel32.dll")]
		extern public static IntPtr LocalFree(IntPtr hMem);

		/// <summary>
		/// This function changes the size or the attributes of a specified local
		/// memory object. The size can increase or decrease.
		/// </summary>
		/// <param name="hMem">[in] Handle to the local memory object to be reallocated.
		/// This handle is returned by either the LocalAlloc or LocalReAlloc function.</param>
		/// <param name="uBytes">[in] New size, in bytes, of the memory block. If fuFlags
		/// specifies the LMEM_MODIFY flag, this parameter is ignored.</param>
		/// <param name="fuFlags">[in] Flag that specifies how to reallocate the local
		/// memory object. If the LMEM_MODIFY flag is specified, this parameter modifies
		/// the attributes of the memory object, and the uBytes parameter is ignored.
		/// Otherwise, this parameter controls the reallocation of the memory object.
		/// The LMEM_MODIFY can be combined with LMEM_MOVEABLE.
		/// If this parameter does not specify LMEM_MODIFY, this parameter can be any
		/// combination of LMEM_MOVEABLE and LMEM_ZEROINIT.</param>
		/// <returns>A handle to the reallocated memory object indicates success.
		/// NULL indicates failure. To get extended error information, call
		/// GetLastError.</returns>
		[DllImport("Kernel32.dll")]
		extern public static IntPtr LocalReAlloc(IntPtr hMem, uint uBytes, uint fuFlags);
	}
}

﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Drawing;

namespace Notes
{

    public class NoteDrawerException : System.Exception
    {
        public NoteDrawerException(string reason) : base(reason) { }
    }

    class NoteRectangle
    {
        public Note note;
        public RectangleF rectangle;

        public NoteRectangle(Note _note, RectangleF _rectangle)
        {
            note = _note;
            rectangle = _rectangle;
        }
    }

    /// <summary>
    /// Creates an empty music sheet and display note on it
    /// </summary>
    class NoteDrawer
    {
        const uint numberOfLines = 5;
        const float lengthBetweenLines = 10;
        const float heigthBetweenStaves = 100;
        const float stavesMarginsSize = 20;
        const float spaceBetweenNotes = 15;
        const float spaceAfterClef = 10;
        const float widthOfNote = lengthBetweenLines;
        float width = 0;
        float height = 0;
        float widthOfStave = 0;
        float heightOfStave = (numberOfLines - 1) * lengthBetweenLines;

        /*
        const uint numberOfLines = 5;
        const float lengthBetweenLines = 15;
        const float heigthBetweenStaves = 120;
        const float stavesMarginsSize = 20;
        const float spaceBetweenNotes = 20;
        const float spaceAfterClef = 10;
        const float widthOfNote = lengthBetweenLines;
        float width = 0;
        float height = 0;
        float widthOfStave = 0;
        float heightOfStave = (numberOfLines - 1) * lengthBetweenLines;
        */

        /// <summary>
        /// the locations of each stave on the graphics control
        /// </summary>
        List<PointF> stavesLocation;

        /// <summary>
        /// the locations of all the places notes can be printed on the graphics control
        /// </summary>
        List<PointF> NotesLocation;

        /// <summary>
        /// the bounding rectangle for each note on the graphics control
        /// </summary>
        List<NoteRectangle> NotesRect;

        /// <summary>
        /// buffer of all the notes that currently shown on the graphics control
        /// </summary>
        List<Note> DrawenNotes;

        // graphics components
        Image bufferImage;
        Graphics bufferGraphics;
        Image GClef;

        public NoteDrawer()
        {
            lock (this)
            {
                stavesLocation = new List<PointF>();
                NotesLocation = new List<PointF>();
                NotesRect = new List<NoteRectangle>();
                DrawenNotes = new List<Note>();
                bufferImage = new Bitmap(1, 1);
                bufferGraphics = Graphics.FromImage(bufferImage);
                Image GClefSource = Recorder.Properties.Resources.GClefPicture;
                GClef = new Bitmap(GClefSource, (int)(heightOfStave * 0.5), (int)(heightOfStave * 1.3));
            }
        }

        /// <summary>
        /// 
        /// </summary>
        /// <param name="graphics"></param>
        /// <param name="background"></param>
        /// <param name="brushSheet"></param>
        /// <param name="brushNote"></param>
        /// <param name="note"></param>
        /// <returns>Number of Notes can be displayed</returns>
        public int Draw(Graphics graphics, Color background, Brush brushSheet, Brush brushNote , Note note = null)
        {
            lock (this)
            {
                UpdateDrawer(graphics, background, brushSheet, brushNote);

                // Draw a new Note
                if (null != note)
                {
                    // Draw a new sheet if current one is full
                    if (DrawenNotes.Count >= NotesLocation.Count)
                    {
                        DrawEmptyMusicSheet(graphics, background, brushSheet);
                        DrawenNotes.Clear();
                        NotesRect.Clear();
                    }

                    int noteIndex = DrawenNotes.Count;
                    DrawNote(bufferGraphics, brushNote, NotesLocation[noteIndex], note);
                    DrawenNotes.Add(note);
                }

                graphics.DrawImage(bufferImage, 0, 0);
            }

            return NotesLocation.Count;
        }

        /// <summary>
        /// Given List of Notes and their colors, simply draw them.
        /// </summary>
        /// <param name="graphics"></param>
        /// <param name="notes"></param>
        /// <param name="notesColors"></param>
        /// <returns>number of notes that can be drawen</returns>
        public int DrawNotes(Graphics graphics, Color background, Brush brushSheet, List<Note> notes, List<Color> notesColors)
        {
            // Redraw music sheet if graphics has changes
            if ((graphics.VisibleClipBounds.Width != this.width) || (graphics.VisibleClipBounds.Height != this.height))
            {
                DrawEmptyMusicSheet(graphics, background, brushSheet);
                graphics.DrawImage(bufferImage, 0, 0);
                return NotesLocation.Count;
            }

            // Draw notes
            if ((null != notes) && (null != notesColors) && (notes.Count <= notesColors.Count))
            {
                for (int noteIndex = 0; noteIndex < notes.Count; noteIndex++)
                {
                    Note note = notes[noteIndex];
                    DrawNote(bufferGraphics,
                        new SolidBrush(notesColors[noteIndex]),
                        NotesLocation[noteIndex],
                        note);
                }
                graphics.DrawImage(bufferImage, 0, 0);
            }
            return NotesLocation.Count;
        }

        public void Clear(Graphics graphics, Color background, Brush brushSheet)
        {
            DrawEmptyMusicSheet(graphics, background, brushSheet);
        }

        /// <summary>
        /// Redraw a note at a specidic location
        /// </summary>
        /// <param name="graphics"></param>
        /// <param name="brushNote"></param>
        /// <param name="note"></param>
        /// <param name="noteIndex"></param>
        public void RedrawNote(Graphics graphics, Brush brushNote, Note note, int noteIndex)
        {
            lock (this)
            {
                if (null == note)
                {
                    return;
                }

                if (NotesLocation.Count <= noteIndex)
                {
                    return; // TODO: throw an exception
                }

                // if want to redraw the last note
                if (0 > noteIndex)
                {
                    noteIndex = DrawenNotes.Count - 1;
                }

                DrawNote(bufferGraphics, brushNote, NotesLocation[noteIndex], note);
                graphics.DrawImage(bufferImage, 0, 0);
            }
        }

        public Note GetNoteOnLocation(Point location)
        {
            lock (this)
            {
                for (int i = 0; i < NotesRect.Count; i++)
                {
                    if (NotesRect[i].rectangle.Contains(location))
                    {
                        return NotesRect[i].note;
                    }
                }
                return null;
            }
        }

        private void UpdateDrawer(Graphics graphics, Color background, Brush brushSheet, Brush brushNote)
        {
            // Redraw music sheet if graphics has changes
            if ((graphics.VisibleClipBounds.Width != width) || (graphics.VisibleClipBounds.Height != height))
            {
                DrawEmptyMusicSheet(graphics, background, brushSheet);

                // If there are too many notes and not enough space for them, remove the oldest notes
                int notesToRemove = (int)DrawenNotes.Count - (int)NotesLocation.Count;
                if (notesToRemove > 0)
                {
                    DrawenNotes.RemoveRange(0, notesToRemove);
                }

                NotesRect.Clear();
                // draw old notes
                for (int noteIndex = 0; noteIndex < DrawenNotes.Count; noteIndex++)
                {
                    Note oldNote = DrawenNotes[noteIndex];
                    DrawNote(bufferGraphics, brushNote, NotesLocation[noteIndex], oldNote);
                }
            }
        }

        /// <summary>
        /// Draw a plain music sheet, contains only stavs.
        /// Also, update the class varibales, to fit the current graphics objects.
        /// (This method migth be called in two cases:
        ///     1. resize - need to change the sheet size & redraw it (including old notes).
        ///     2. new page - create a blank sheet.
        /// </summary>
        /// <param name="graphics">new graphics object</param>
        private void DrawEmptyMusicSheet(Graphics graphics, Color background, Brush brushSheet)
        {
            width = graphics.VisibleClipBounds.Width;
            height = graphics.VisibleClipBounds.Height;
            widthOfStave = width - 2 * stavesMarginsSize;
            // double buffeing
            bufferImage = new Bitmap((int)width, (int)height);
            bufferGraphics = Graphics.FromImage(bufferImage);
            bufferGraphics.Clear(background);

            stavesLocation.Clear();
            NotesLocation.Clear();

            // Calculate new Staves and Note Locations.
            PointF currentStaveLocation = new PointF(stavesMarginsSize, heigthBetweenStaves);
            while (currentStaveLocation.Y + heightOfStave + heigthBetweenStaves <= height)
            {
                stavesLocation.Add(currentStaveLocation);

                PointF currentNoteLocation = new PointF(currentStaveLocation.X + GClef.Width + spaceAfterClef,
                                                        currentStaveLocation.Y);
                while (currentNoteLocation.X + widthOfNote + spaceBetweenNotes < width - stavesMarginsSize)
                {
                    NotesLocation.Add(currentNoteLocation);
                    currentNoteLocation.X += widthOfNote + spaceBetweenNotes;
                }
                currentStaveLocation.Y += heightOfStave + heigthBetweenStaves;
            }

            // print staves
            foreach (PointF staveLocation in stavesLocation)
            {
                DrawStave(bufferGraphics, brushSheet, staveLocation);
            }
        }

        private void DrawNote(Graphics graph, Brush brush, PointF point, Note note)
        {
            /* The starting position is E' (inner index 51).
             * Based on the current note distance from E", we will set it's location. */
            int distanceFromE = note.LineIndex - 51;
            PointF ellipseBase = new PointF(point.X, point.Y - distanceFromE * lengthBetweenLines / 2F);
            SizeF ellipseSize = new SizeF(widthOfNote, lengthBetweenLines);
            RectangleF ellipse = new RectangleF(ellipseBase, ellipseSize);
            RectangleF noteRect = new RectangleF(ellipseBase, ellipseSize);

            // Figure out note's line location
            PointF LineStart, LineEnd;
            bool noteFlagDown = false;
            if (note.LineIndex > 48)
            {
                noteFlagDown = false;
                LineStart = new PointF(ellipse.X, ellipse.Y + lengthBetweenLines / 2F);
                LineEnd = new PointF(LineStart.X, LineStart.Y + 3.5F * lengthBetweenLines);

                noteRect.Y = ellipse.Y;
                noteRect.Height = LineEnd.Y - ellipse.Y;
            }
            else
            {
                noteFlagDown = true;
                LineStart = new PointF(ellipse.X + widthOfNote, ellipse.Y + lengthBetweenLines / 2F);
                LineEnd = new PointF(LineStart.X, LineStart.Y - 3.5F * lengthBetweenLines);

                noteRect.Y = LineEnd.Y;
                noteRect.Height = ellipse.Bottom - LineEnd.Y;
            }
            PointF[] noteLine = { LineStart , LineEnd};


            // For each note length, print matchig ellipse shape & line 
            graph.DrawEllipse(new Pen(brush, 1F), ellipse);
            graph.FillEllipse(brush, ellipse);
            RectangleF innerEllipse;

            switch ((int)(note.Length * 1000))
            {
                case 125:
                    graph.DrawLines(new Pen(brush, 2F), noteLine);
                    if (noteFlagDown)
                    {
                        DrawFlagDown(graph, brush, LineEnd.X, LineEnd.Y, widthOfNote / 1.5F, lengthBetweenLines * 3);
                    }
                    else
                    {
                        DrawFlagUp(graph, brush, LineEnd.X, LineEnd.Y, widthOfNote / 1.5F, lengthBetweenLines * 3);
                    }
                    break;
                case 250:
                    graph.DrawLines(new Pen(brush, 2F), noteLine);
                    break;
                case 375:
                    graph.FillEllipse(brush, ellipse.X + widthOfNote * 1.2F, ellipse.Y + ellipse.Height / 3F, 4, 4);

                    innerEllipse = ellipse;
                    innerEllipse.Height -= 6;
                    innerEllipse.Y += 3;
                    graph.FillEllipse(new SolidBrush(Color.White), innerEllipse);
                    graph.DrawLines(new Pen(brush, 2F), noteLine);
                    break;
                case 500:
                    innerEllipse = ellipse;
                    innerEllipse.Height -= 6;
                    innerEllipse.Y += 3;
                    graph.FillEllipse(new SolidBrush(Color.White), innerEllipse);
                    graph.DrawLines(new Pen(brush, 2F), noteLine);
                    break;
                case 1000:
                    innerEllipse = ellipse;
                    innerEllipse.Height -= 6;
                    innerEllipse.Y += 3;
                    graph.FillEllipse(new SolidBrush(Color.White), innerEllipse);
                    break;
                default:
                    break;
            }

            NotesRect.Add(new NoteRectangle(note, noteRect));

            if (note.IsSharp)
            {
                string sharp = "\u266F";
                Font font = new Font("Ariel", widthOfNote);
                graph.DrawString(sharp, font, brush, new PointF(ellipseBase.X - widthOfNote, ellipseBase.Y - 5));
            }

            // check if need to add vertical small lines for higher/lower notes
            if (point.Y - ellipseBase.Y >= lengthBetweenLines)
            {
                PointF littleLineStart = new PointF(point.X - 2, point.Y);
                PointF littleLineEnd = new PointF(point.X + widthOfNote + 2, point.Y);
                while (littleLineStart.Y - ellipseBase.Y >= lengthBetweenLines)
                {
                    graph.DrawLine(new Pen(brush, 1F), littleLineStart, littleLineEnd);
                    littleLineStart.Y = littleLineEnd.Y = littleLineEnd.Y - lengthBetweenLines;
                }
            }

            float stave_bottom = point.Y + (numberOfLines - 1) * lengthBetweenLines;
            if (ellipse.Bottom - stave_bottom >= lengthBetweenLines)
            {
                stave_bottom += lengthBetweenLines;
                PointF littleLineStart = new PointF(point.X - 2, stave_bottom);
                PointF littleLineEnd = new PointF(point.X + widthOfNote + 2, stave_bottom);
                while (ellipse.Bottom - littleLineStart.Y > 0)
                {
                    graph.DrawLine(new Pen(brush, 1F), littleLineStart, littleLineEnd);
                    littleLineStart.Y = littleLineEnd.Y = littleLineEnd.Y + lengthBetweenLines;
                }
            }
        }

        private void DrawStave(Graphics graph, Brush brush, PointF point)
        {
            Pen pen = new Pen(brush);

            // draw vertical lines, at the begining and end of the stave
            graph.DrawLine(pen,
                point,
                new PointF(point.X, point.Y + heightOfStave));

            graph.DrawLine(pen,
                new PointF(point.X + widthOfStave, point.Y),
                new PointF(point.X + widthOfStave, point.Y + heightOfStave));

            // draw stave's lines
            for (int i = 0; i < numberOfLines; i++)
            {
                graph.DrawLine(pen,
                    new PointF(point.X, point.Y + i * lengthBetweenLines),
                    new PointF(point.X + widthOfStave, point.Y + i * lengthBetweenLines));
            }

            // draw G-clefs
            graph.DrawImage(GClef, new PointF(point.X, point.Y));
        }

        private void DrawFlagDown(Graphics graph, Brush brush, float x, float y, float width, float height)
        {
            PointF[] points = new PointF[5];
            points[0].X = x; points[0].Y = y;
            points[1].X = x + width; points[1].Y = y + height / 2;
            points[2].X = x + width / 3; points[2].Y = y + height;
            points[3].X = x + width * 2 / 3; points[3].Y = y + height / 2;
            points[4].X = x; points[4].Y = y + height / 5;
            graph.FillClosedCurve(brush, points);
        }

        private void DrawFlagUp(Graphics graph, Brush brush, float x, float y, float width, float height)
        {
            DrawFlagDown(graph, brush, x, y, width, -height);
        }
    }
}

﻿/*******************************************************************
 * Class Name: NotesDB
 * Purpose: - notes detection. Given a frequency in Hz, it return
 *          the note (as string). The information is first initialized
 *          from a notes information table.
 *          - given few notes samples, it analyses them and return the note.
 * Author: Hila Shmuel, 
 * Date: 29/07/2011
 *******************************************************************/

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.IO;

namespace Notes
{
    /// <summary>
    /// represantation of a musical note
    /// </summary>
    public class Note
    {
        /// <summary>
        /// note scientific name (without ocatve): "A", "A#", "B",...
        /// </summary>
        public string NoteDescription;

        /// <summary>
        /// note's ocatves - from C-1 to G9 (-1,...9)
        /// </summary>
        public short Octave;

        /// <summary>
        /// note's pitch
        /// </summary>
        public float Frequency;

        /// <summary>
        /// note's MIDI number - from 0..127
        /// </summary>
        public byte MIDI;

        /// <summary>
        /// an internal index used for drawing the note on the correct line.
        /// with this numbering, a note "X" and "X#" would have the same value.
        /// example:
        ///     notes - "C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"
        ///     index -  0,   0,    1,   1,    2,   3,   3,    4,   4,    5,   5,    6
        /// </summary>
        public byte LineIndex;

        /// <summary>
        /// does the note has sharp or flat
        /// </summary>
        public bool IsSharp;

        /// <summary>
        /// the note abc notation
        /// </summary>
        public string ABC;

        /// <summary>
        /// length of the note, in milliseconds
        /// </summary>
        public int Duration;

        /// <summary>
        /// length of the note: 1/2, 1/4, 1/8,...
        /// </summary>
        public float Length;


        /// <summary>
        /// Constructor of the note class
        /// </summary>
        /// <param name="noteDescription"></param>
        /// <param name="octave"></param>
        /// <param name="frequency"></param>
        /// <param name="midi"></param>
        /// <param name="lineIndex"></param>
        /// <param name="isSharp"></param>
        /// <param name="abc"></param>
        /// <param name="duration"></param>
        /// <param name="length"></param>
        public Note(string noteDescription,
            short octave,
            float frequency,
            byte midi,
            byte lineIndex,
            bool isSharp = false,
            string abc = "",
            int duration = 0,
            float length = 0.25F)
        {
            NoteDescription = noteDescription;
            Octave = octave;
            Frequency = frequency;
            MIDI = midi;
            LineIndex = lineIndex;
            IsSharp = isSharp;
            ABC = abc; // TODO: don't make ABC as deafult, create it in the NoteTable
            Duration = duration;
            Length = length;
        }    
    }

    /// <summary>
    /// a comparer for comparing between notes based on their frequencies
    /// </summary>
    public class NoteComparer : IComparer<Note>
    {
        /// <summary>
        /// a comparer for comparing between notes based on their frequencies
        /// </summary>
        /// <param name="x">first note to compare</param>
        /// <param name="y">second note to compare</param>
        /// <returns></returns>
        public int Compare(Note x, Note y)
        {
            return x.Frequency.CompareTo(y.Frequency);
        }
    }

    /// <summary>
    /// create a Table contains notes and their descriptions,
    /// and allow search note given frequency
    /// </summary>
    class NotesDB
    {
        /// <summary>
        /// Table of notes, With MIDI 0... 127
        /// </summary>
        List<Note> NotesTable;

        /// <summary>
        /// a note comparer
        /// </summary>
        NoteComparer NotesComparer;

        /// <summary>
        /// construct a new notes table
        /// </summary>
        public NotesDB()
        {
            NotesTable = CreateNotesTable();
            NotesComparer = new NoteComparer();
        }

        /// <summary>
        /// Get a note given its MIDI number
        /// </summary>
        /// <param name="MIDI">a MIDI number describing a note</param>
        /// <returns>a Note with that MIDI</returns>
        public Note GetNote(byte MIDI)
        {
            if (MIDI < 0 || MIDI > 127)
            {
                return null;
            }
            else
            {
                return NotesTable[MIDI];
            }
        }

        /// <summary>
        /// Get a note given its ABC representation 
        /// </summary>
        /// <param name="ABC">an ABC string</param>
        /// <returns>note</returns>
        public Note GetNoteByABC(string ABC)
        {
            foreach (Note note in NotesTable)
            {
                if (note.ABC == ABC)
                {
                    return note;
                }
            }
            return null;
        }

        /// <summary>
        /// create a list of notes, with MIDI index 0... 127
        /// </summary>
        /// <returns>list of notes and information</returns>
        private List<Note> CreateNotesTable()
        {
            List<Note> notesTable = new List<Note>();
            string[] notesDescription = { "C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B" };
            bool[] sharp = { false, true, false, true, false, false, true, false, true, false, true, false };

            // search for Helmholtz pitch notation
            int germanNotataionMarks = -8; // C,,, C,, C, C c c' c'' c''' c'''' c''''' c''''''
            string noteDescription = "";
            int octave = -1;
            double frequency = 0;
            byte midi = 0;
            byte lineIndex = 0;
            bool isSharp = false;
            string abc = "";
            int noteIndex = 0;

            for (midi = 0; midi < 128; midi++)
            {
                frequency = 440.0 * Math.Pow(2, (midi - 69.0) / 12.0);
                noteIndex = midi % notesDescription.Length;
                octave = midi / notesDescription.Length - 1;
                noteDescription = notesDescription[noteIndex];
                isSharp = sharp[noteIndex];

                //ABC
                if (isSharp)
                {
                    abc = "^" + noteDescription[0];
                }
                else
                {
                    abc = noteDescription;
                }

                if (noteIndex == 0)
                {
                    germanNotataionMarks++;
                }
                if (germanNotataionMarks < 0)
                {
                    abc = abc.ToUpper();
                    for (int i = 0; i < Math.Abs(germanNotataionMarks) - 1; i++)
                    {
                        abc += ",";
                    }
                }
                else
                {
                    abc = abc.ToLower();
                    for (int i = 0; i < Math.Abs(germanNotataionMarks); i++)
                    {
                        abc += "'";
                    }
                } 

                notesTable.Add(new Note(noteDescription,
                                        (short)octave,
                                        (float)frequency,
                                        (byte)midi,
                                        lineIndex,
                                        isSharp,
                                        abc));
                if (!isSharp)
                {
                    lineIndex++;
                }
            }

            return notesTable;
        }

        /// <summary>
        /// find note base on given frequency
        /// </summary>
        /// <param name="frequency">pitch, frequency in Hertz</param>
        /// <returns>the note that has the closest pitch to the given frequency</returns>
        public Note FindNote(float frequency)
        {
            Note note = new Note("", 0, frequency, 0, 0);
            int index = NotesTable.BinarySearch(note, NotesComparer);

            if (0 <= index)
            {
                return NotesTable[index];
            }

            index = ~index;

            if ((0 <= index) && (index < NotesTable.Count))
            {
                if (index == 0)
                {
                    return NotesTable[0];
                }
                else if (Math.Abs(NotesTable[index - 1].Frequency - frequency) >= Math.Abs(NotesTable[index].Frequency - frequency))
                {
                    return NotesTable[index];
                }
                else
                {
                    return NotesTable[index - 1];
                }
            }
            return new Note("", 0, 0, 0, 0);
        }
    }
}

