﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Drawing;
using System.Threading;
using Notes;


namespace Recorder
{
    /// <summary>
    /// The RecorderHero class
    /// </summary>
    class RecorderHero : IDisposable
    {
        /// <summary>
        /// Draws the notes on graphics object
        /// </summary>
        private NoteDrawer Drawer;

        /// <summary>
        /// Holds the ABC notes
        /// </summary>
        private RecordingData AbcData;

        /// <summary>
        /// Thread that runs over the notes, and update the graphics
        /// </summary>
        private Thread RecorderHeroThread;

        /// <summary>
        /// Saves the graphics object, should be accsessed by the recorderHeroThread and when resized.
        /// </summary>
        private Graphics NotesGraphics;


        /// <summary>
        /// The colors of the notes
        /// </summary>
        private List<Color> NotesColors;

        /// <summary>
        /// current note to be played
        /// </summary>
        private int CurrentNoteIndex;

        /// <summary>
        /// Number of notes that can be displayed in music sheet
        /// </summary>
        private int NotesPerPage;

        /// <summary>
        /// The first note to be displayed in the current music sheet
        /// </summary>
        private int FirstNoteInPage;

        /// <summary>
        /// Boolean to tell if currently playing.
        /// </summary>
        private bool m_isPlaying;

        /// <summary>
        /// Is the RecorderHero currently active
        /// </summary>
        public bool isPlaying
        {
            get { return m_isPlaying; }
        }

        /// <summary>
        /// Sleep multiplier by the notes duration
        /// </summary>
        private float m_sleepMultiplier = 1f;

        /// <summary>
        /// How mutch to speed up/down the notes duration
        /// </summary>
        public float SleepMultiplier
        {
            get
            {
                return m_sleepMultiplier;
            }
            set
            {
                this.m_sleepMultiplier = value;
            }
        }

        private Color REGULAR_COLOR = Color.Black;
        private Color WRONG_COLOR = Color.FromArgb(240, 230, 53, 98);
        private Color RIGHT_COLOR = Color.FromArgb(240, 33, 250, 98);
        private Color CURRENT_COLOR = Color.FromArgb(240, 63, 149, 220);



        /// <summary>
        /// Open a new RecorderHero instance
        /// </summary>
        /// <param name="graphics">The notes music sheet panel</param>
        /// <param name="abcFilePath">ABC File contains notes</param>
        public RecorderHero(Graphics graphics, string abcFilePath)
        {
            Drawer = new NoteDrawer();

            // convert ABC file to notes
            AbcData = AbcParser.AbcToNotes(abcFilePath);

            // Creating a new music sheet, with first notes in it
            Restart(graphics);
        }

        /// <summary>
        /// Starts a new thread that runs over the notes, and display the current note to be played
        /// </summary>
        public void Start()
        {
            m_isPlaying = true;
            RecorderHeroThread = new Thread(new ThreadStart(NotesIteration));
            RecorderHeroThread.Start();
        }

        /// <summary>
        /// Stops the thread that should runs over the notes
        /// </summary>
        public void Stop()
        {
            m_isPlaying = false;
            if (null != RecorderHeroThread)
            {
                RecorderHeroThread.Join();
            }
        }

        /// <summary>
        /// Dispose the recorderHero object
        /// </summary>
        public void Dispose()
        {
            Stop();
        }

        /// <summary>
        /// Notify which note was just played
        /// </summary>
        /// <param name="currentNote">Note that was just played</param>
        public void UpdateCurrentNote(Note currentNote)
        {
            lock (this)
            {
                if (CurrentNoteIndex >= AbcData.Notes.Count)
                {
                    return;
                }
                if (currentNote.MIDI == AbcData.Notes[CurrentNoteIndex].MIDI)
                {
                    NotesColors[CurrentNoteIndex] = RIGHT_COLOR;

                    // Draw with current note as correct
                    int a = FirstNoteInPage;
                    int b = Math.Min(FirstNoteInPage + NotesPerPage, AbcData.Notes.Count)
                        - FirstNoteInPage;

                    NotesPerPage = Drawer.DrawNotes(NotesGraphics,
                        Color.White,
                        new SolidBrush(Color.Black),
                        AbcData.Notes.GetRange(a, b),
                        NotesColors.GetRange(a, b));
                }
            }
        }

        /// <summary>
        /// When the music sheet panel changes, change the internal graphics object & repaint notes
        /// </summary>
        /// <param name="graphics"></param>
        public void OnPaint(Graphics graphics)
        {
            lock (this)
            {
                NotesGraphics = graphics;

                // Create new Music Sheet - get number of notes in current music sheet
                NotesPerPage = Drawer.DrawNotes(graphics,
                    Color.White,
                    new SolidBrush(Color.Black),
                    null,
                    null);

                if (FirstNoteInPage + NotesPerPage <= CurrentNoteIndex)
                {
                    FirstNoteInPage = CurrentNoteIndex;
                }

                // give that number of notes
                int a = FirstNoteInPage;
                int b = Math.Min(FirstNoteInPage + NotesPerPage, AbcData.Notes.Count)
                    - FirstNoteInPage;

                NotesPerPage = Drawer.DrawNotes(graphics,
                    Color.White,
                    new SolidBrush(Color.Black),
                    AbcData.Notes.GetRange(a, b),
                    NotesColors.GetRange(a, b));
            }
        }

        public Note GetCurrentNote()
        {
            if (m_isPlaying && 0 <= CurrentNoteIndex && CurrentNoteIndex < AbcData.Notes.Count)
            {
                return AbcData.Notes[CurrentNoteIndex];
            }
            else
            {
                return null;
            }
        }

        /// <summary>
        /// Creating a new music sheet with the notes data
        /// </summary>
        /// <param name="graphics"></param>
        private void Restart(Graphics graphics)
        {
            NotesColors = new List<Color>();
            FirstNoteInPage = 0;
            CurrentNoteIndex = 0;
            m_isPlaying = false;
            NotesGraphics = graphics;

            for (int i = 0; AbcData.Notes.Count > i; ++i)
            {
                NotesColors.Add(REGULAR_COLOR);
            }

            OnPaint(graphics);
        }

        /// <summary>
        /// This function should be running in a different thread, and updates the graphics
        /// </summary>
        private void NotesIteration()
        {
            while (m_isPlaying)
            {
                int CurrentNoteDuration = 0;

                lock (this)
                {
                    // Some kind of documentation
                    if (CurrentNoteIndex >= NotesColors.Count)
                    {
                        return;
                    }

                    NotesColors[CurrentNoteIndex] = CURRENT_COLOR;

                    // Check if it's the first note in the page
                    if (FirstNoteInPage == CurrentNoteIndex)
                    {
                        Drawer.Clear(NotesGraphics, Color.White, new SolidBrush(Color.Black));
                    }

                    // Draw notes
                    int a = FirstNoteInPage;
                    int b = Math.Min(FirstNoteInPage + NotesPerPage, AbcData.Notes.Count)
                        - FirstNoteInPage;

                    NotesPerPage = Drawer.DrawNotes(NotesGraphics,
                        Color.White,
                        new SolidBrush(Color.Black),
                        AbcData.Notes.GetRange(a, b),
                        NotesColors.GetRange(a, b));

                    CurrentNoteDuration = AbcData.Notes[CurrentNoteIndex].Duration;
                }

                Thread.Sleep((int)((float)CurrentNoteDuration * m_sleepMultiplier));

                lock (this)
                {
                    // Check if it's the last note in the page
                    if (FirstNoteInPage + NotesPerPage == CurrentNoteIndex)
                    {
                        FirstNoteInPage = CurrentNoteIndex + 1;
                    }

                    // If no right answer yet, color this note as wrong.
                    if (NotesColors[CurrentNoteIndex] != RIGHT_COLOR)
                    {
                        NotesColors[CurrentNoteIndex] = WRONG_COLOR;
                    }

                    // Advance note
                    ++CurrentNoteIndex;

                    // Check if the previous note was the last note
                    if (CurrentNoteIndex == AbcData.Notes.Count)
                    {
                        // Draw again
                        int a = FirstNoteInPage;
                        int b = Math.Min(FirstNoteInPage + NotesPerPage, AbcData.Notes.Count)
                            - FirstNoteInPage;

                        NotesPerPage = Drawer.DrawNotes(NotesGraphics,
                            Color.White,
                            new SolidBrush(Color.Black),
                            AbcData.Notes.GetRange(a, b),
                            NotesColors.GetRange(a, b));

                        // This was last note
                        m_isPlaying = false;
                        return;
                    }
                }
            }
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Drawing;
using System.Threading;
using Notes;

namespace Recorder
{
    /// <summary>
    /// Given the ABC file with notes, while playing in the recorder,
    /// the class checks whether the note that has been play is the correct one,
    /// and display it. In other words: Like GuitarHero, but for Recorder.
    /// 
    /// the image is updating only when new notes are given,
    /// so it depends in the incoming rate of the notes.
    /// 
    /// </summary>
    public class RecorderHero
    {
        /// <summary>
        /// The music data, notes to be played
        /// </summary>
        private RecordingData recodingData;

        /// <summary>
        /// color of each note - black (noraml), red (error), green (correct)
        /// </summary>
        private List<Color> NotesColors;

        /// <summary>
        /// Responsible for creating the music sheet graphcis
        /// </summary>
        private NoteDrawer Drawer;

        /// <summary>
        /// The note that is currently playing
        /// </summary>
        private int CurrentNoteIndex = -1;

        /// <summary>
        /// The index of the first note in the current music sheet
        /// </summary>
        private int FirstNoteInPage = 0;

        /// <summary>
        /// The number of notes that can be displayed in one music sheet page
        /// </summary>
        private int NotesCountPerPage = 0;

        /// <summary>
        /// The time the recording start
        /// </summary>
        private int StartTime = 0;

        /// <summary>
        /// Decide whether to update the notes ot not.
        /// </summary>
        private bool IsPlaying = false;


        private Thread PlayNotesThread = null;

        bool ClearNeeded = false;

        /// <summary>
        /// Create a music sheet with the given notes
        /// </summary>
        /// <param name="graphics">Where to paint the music sheet</param>
        /// <param name="abcFilePath">The notes to be played</param>
        public RecorderHero(Graphics graphics, string abcFilePath)
        {
            Drawer = new NoteDrawer();

            // convert to notes
            recodingData = AbcParser.AbcToNotes(abcFilePath);

            // Creating a new music sheet, with first notes in it
             Restart(graphics);
        }

        /// <summary>
        /// restart the RecorderHero - notes index and music sheet.
        /// </summary>
        /// <param name="graphics"></param>
        public void Restart(Graphics graphics)
        {
            lock (this)
            {
                // Creating a new music sheet, with first notes in it
                CurrentNoteIndex = 0;
                FirstNoteInPage = 0;
                NotesCountPerPage = 0;
                StartTime = System.Environment.TickCount;
                IsPlaying = false;

                // Set initial notes colors
                NotesColors = new List<Color>(recodingData.Notes.Count);
                for (int i = 0; i < recodingData.Notes.Count; i++)
                {
                    NotesColors.Add(Color.Black);
                }

                // Create new Music Sheet - get number of notes in current music sheet
                Update(graphics);

                Thread PlayNotesThread = new Thread(new ThreadStart(PlayNotes));
                PlayNotesThread.Start();
            }
        }

        /// <summary>
        /// Given the note that is currently played, Update the music sheet
        /// </summary>
        /// <param name="graphics"></param>
        /// <param name="note"></param>
        /// <returns> the note that should be played right now</returns>
        public Note UpdateNote(Graphics graphics, Note note)
        {
            lock (this)
            {
                if (0 <= CurrentNoteIndex)
                {
                    // clear music sheet
                    if (ClearNeeded)
                    {
                        Drawer.Clear(graphics, Color.White, new SolidBrush(Color.Black));
                        ClearNeeded = false;
                    }

                    if (CurrentNoteIndex == -1)
                    {
                        //for (int i = 0; i < NotesColors.Count; i++)
                        {
                            NotesColors[NotesColors.Count - 1] = Color.Black;
                        }
                    }

                    if (note.MIDI == recodingData.Notes[CurrentNoteIndex].MIDI)
                    {
                        NotesColors[CurrentNoteIndex] = Color.Green;
                    }
                    else
                    {
                        NotesColors[CurrentNoteIndex] = Color.Red;
                    }

                    Update(graphics);
                    if (-1 != CurrentNoteIndex)
                    {
                        return recodingData.Notes[CurrentNoteIndex];
                    }

                }

            }
            return null;
        }

        /// <summary>
        /// When resize, or need to change note's color, redraw the music sheet
        /// </summary>
        /// <param name="graphics"></param>
        public void Update(Graphics graphics)
        {
            lock (this)
            {
                // Create new Music Sheet - get number of notes in current music sheet
                NotesCountPerPage = Drawer.DrawNotes(graphics,
                    Color.White,
                    new SolidBrush(Color.Black),
                    null,
                    null);

                // give that number of notes -TODO: FIX THIS STATEMENT LIMIT ERROR
                int min = Math.Min(NotesCountPerPage, recodingData.Notes.Count);
                if (FirstNoteInPage < min)
                {
                    NotesCountPerPage = Drawer.DrawNotes(graphics,
                        Color.White,
                        new SolidBrush(Color.Black),
                        recodingData.Notes.GetRange(FirstNoteInPage, min),
                        NotesColors.GetRange(FirstNoteInPage, min));
                }
            }
        }

        /// <summary>
        /// Notify the RecorderHero that the user has 
        /// </summary>
        /// <param name="graphics"></param>
        public void Play(Graphics graphics)
        {
            IsPlaying = true;
            StartTime = System.Environment.TickCount;

            // Update graphics
            Update(graphics);
        }

        /// <summary>
        /// This function runs in a different thread, and loop over the notes,
        /// (based on their duration), and updates the CurrentNoteIndex 
        /// </summary>
        private void PlayNotes()
        {
            int duration = 0;
            int noteIndex = 0;

            for (int i = 0; i < recodingData.Notes.Count; i++)
            {
                lock (this)
                {
                    CurrentNoteIndex = i;
                    if (FirstNoteInPage + NotesCountPerPage <= i)
                    {
                        FirstNoteInPage = i;
                        ClearNeeded = true;
                    }
                    duration = recodingData.Notes[CurrentNoteIndex].Duration * 2;
                    noteIndex = CurrentNoteIndex;
                }


            }

            Thread.Sleep(duration);
            lock (this)
            {
                NotesColors[noteIndex] = Color.Black;
                CurrentNoteIndex = -1;
            }
        }
    }
}

